import{_ as t,c as e,o as i,d as p}from"./app.661b9247.js";const m=JSON.parse('{"title":"GitHub快速入门","description":"","frontmatter":{},"headers":[{"level":2,"title":"版本管理","slug":"版本管理","link":"#版本管理","children":[{"level":3,"title":"SVN","slug":"svn","link":"#svn","children":[]},{"level":3,"title":"Git","slug":"git","link":"#git","children":[]}]},{"level":2,"title":"什么GitHub","slug":"什么github","link":"#什么github","children":[]},{"level":2,"title":"安装与配置Git","slug":"安装与配置git","link":"#安装与配置git","children":[{"level":3,"title":"安装","slug":"安装","link":"#安装","children":[]},{"level":3,"title":"配置","slug":"配置","link":"#配置","children":[]},{"level":3,"title":"创建账户","slug":"创建账户","link":"#创建账户","children":[]},{"level":3,"title":"配置SSH","slug":"配置ssh","link":"#配置ssh","children":[]}]},{"level":2,"title":"建立仓库","slug":"建立仓库","link":"#建立仓库","children":[{"level":3,"title":"远程仓库","slug":"远程仓库","link":"#远程仓库","children":[]},{"level":3,"title":"本地仓库","slug":"本地仓库","link":"#本地仓库","children":[]},{"level":3,"title":"重要命令","slug":"重要命令","link":"#重要命令","children":[]},{"level":3,"title":"分支","slug":"分支","link":"#分支","children":[]},{"level":3,"title":"master分支","slug":"master分支","link":"#master分支","children":[]},{"level":3,"title":"分支相关命令","slug":"分支相关命令","link":"#分支相关命令","children":[]},{"level":3,"title":"版本回溯","slug":"版本回溯","link":"#版本回溯","children":[]},{"level":3,"title":"git reset详解","slug":"git-reset详解","link":"#git-reset详解","children":[]}]}],"relativePath":"Document/GitHub的使用/GitHub快速入门.md","lastUpdated":1664267725000}'),r={name:"Document/GitHub的使用/GitHub快速入门.md"},a=p('<h1 id="github快速入门" tabindex="-1">GitHub快速入门 <a class="header-anchor" href="#github快速入门" aria-hidden="true">#</a></h1><p>GitHub文档：<a href="https://docs.github.com/cn" target="_blank" rel="noreferrer">GitHub Documentation</a></p><p>Git 备忘清单（github-cheat-sheet）：<a href="https://docs.github.com/cn/get-started/quickstart/git-cheatsheet" target="_blank" rel="noreferrer">Git 备忘清单 - GitHub Docs</a></p><blockquote><p>当您忘记命令或不想在 CLI 中使用帮助时，此 Git 备忘清单可节省时间。</p><p>很快掌握所有可用的 Git 命令可能是一项艰巨的任务。 可以使用“<a href="https://training.github.com/" target="_blank" rel="noreferrer">Git 速查表</a>”快速参考常用命令。 “Using Git（使用 Git）”备忘清单有多种语言版本。</p><p>此外，请查看 <a href="https://docs.github.com/cn/articles/git-and-github-learning-resources" target="_blank" rel="noreferrer">Git 和 GitHub 学习资源</a>页，该页链接到指南、视频等。</p></blockquote><hr><p>GitHub在程序开发领域家喻户晓，现在几乎整个互联网的开发者都将版本管理工具GitHub作为版本控制的首选，甚至像笔者这样非开发者，一名和每天和数据打交道的人也在使用GitHub，目的主要有：</p><ul><li><p>查找资料：GitHub上有很多国内外大神开源的数据挖掘、机器学习的资料、代码，笔者直接fork或者clone下来学习</p></li><li><p>技术交流：通过对开源项目提出issue，能够起到技术交流的效果</p></li><li><p>个人展示：现在互联网领域中，如果一个程序员在GitHub上有一个很好的开源项目，必定是会备受关注。因此GitHub实际上是一个很好的展示个人实力的舞台，或许它能够让你受到招聘人员的青睐</p></li></ul><p>github作为全球最大的开源软件项目托管平台，相信很多程序员都在使用，不仅仅是因为它可以免费的作为我们公有或者私有的代码仓库，更因为github上面有大量的开源学习项目或资源，秉着开源自由的理念，吸引了大量的个人或者企业开发者。</p><p>github将所有的改动行为称为contributions，包括commit，pr, code review,isssue,fork等等。</p><p>github有个叫活动概览(Activity overview)的功能，将contributions按照下面四个象限进行分类统计：</p><ul><li><p>Commits：建仓、提交代码或fork等会触发</p></li><li><p>Pull requests：指开发者在本地对源代码进行更改后，向 GitHub 中托管的 Git 仓库请求合并的功能。</p></li><li><p>Code review：预览代码</p></li><li><p>Issues：用于 BUG 报告、功能添加、方向性讨论等，将这些以 Issue 形式进行管理。</p></li></ul><h5 id="github使用技巧" tabindex="-1">Github使用技巧： <a class="header-anchor" href="#github使用技巧" aria-hidden="true">#</a></h5><p>很多人搜索github，但是芸芸众生，要找到自己想要的项目犹如海底捞针一般，今天教大家几项神技，可以快速找到自己想要的内容。</p><p>1、按star数目搜索，比如JavaScript，要求星数，这样就能获取star数目最多的项目</p><p>2、follow一些github上面的大牛</p><p>请登录：<a href="https://github-ranking.com/" target="_blank" rel="noreferrer">https://github-ranking.com/</a></p><p>国内大牛：<a href="http://outofmemory.cn/github/" target="_blank" rel="noreferrer">http://outofmemory.cn/github/</a></p><p>这里是搜索名人的网址：<a href="https://github.com/search" target="_blank" rel="noreferrer">Code Search · GitHub</a></p><p>高级搜索：<a href="https://github.com/search/advanced" target="_blank" rel="noreferrer">GitHub · Where software is built</a></p><p>3、Awesome + 你的关键字：搜索一些优秀的框架、教程、项目等</p><p>4、看一些搜索技巧，设定条件进行搜索</p><p>地址：<a href="https://help.github.com/articles/searching-repositories/" target="_blank" rel="noreferrer">搜索仓库 - GitHub Docs</a></p><p>5、通过readme看看人家是否发出pull request</p><p>看看这篇文章：<a href="http://blog.csdn.net/qianlong4526888/article/details/11529981" target="_blank" rel="noreferrer">如何在github中贡献自己的力量_乾龙_Heron的博客-CSDN博客</a></p><p>6、看explore推荐</p><p><a href="https://github.com/explore" target="_blank" rel="noreferrer">Explore GitHub · GitHub</a></p><p>7、看看其他</p><p><a href="http://blog.sina.com.cn/s/blog_4e60b09d0102vcso.html" target="_blank" rel="noreferrer">新浪博客</a></p><p>8、直接github上搜fackbook或者其他，可以看到他们的最新作品</p><p><strong>可以说，正式GitHub，让社会化全员编程成为了现实。</strong></p><h2 id="版本管理" tabindex="-1">版本管理 <a class="header-anchor" href="#版本管理" aria-hidden="true">#</a></h2><p>版本管理就是管理更新的历史记录。Git出现之前，人们主要是使用Subversion（简称为SVN）作为版本控制的工具。</p><h3 id="svn" tabindex="-1">SVN <a class="header-anchor" href="#svn" aria-hidden="true">#</a></h3><p>SVN是属于<strong>集中型</strong>的版本管理系统，其特点是<strong>将仓库集中存放在服务器中，所以只存在一个仓库</strong>。集中型将所有特点是方便管理，但是如果开发者所处的环境无法联网，则无法获取到最新的源码，进而无法进行开发工作。</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/2942439a8eb248d88a9b1e1610b87f8a~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><h3 id="git" tabindex="-1">Git <a class="header-anchor" href="#git" aria-hidden="true">#</a></h3><p>Git是<strong>分散型</strong>的版本管理系统。从下图中我们可以观察出来，GitHub将仓库fork给每个用户。fork的仓库和原始的仓库是两个不同的仓库，开发者是可以随意编辑的。</p><p>Fork的过程其实就是将某个仓库复制到自己的账户下</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/cffee4cfb7e6414d96abac58a67fdad4~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><h2 id="什么github" tabindex="-1">什么GitHub <a class="header-anchor" href="#什么github" aria-hidden="true">#</a></h2><p>GitHub是一个基于Git的代码托管平台。如果是付费用户可以建立自己的私人仓库，一般用户的话只能建立公用仓库，也就是说仓库的代码必须是公开的。到底Git和GitHub有什么区别呢？</p><p>在Git中，开发者将源代码存入名叫“Git仓库”的资料库中，方便使用；而GitHub则是在网络上提供Git仓库的一项服务</p><p>GitHub上公开的源代码都是通过Git进行管理的。</p><h2 id="安装与配置git" tabindex="-1">安装与配置Git <a class="header-anchor" href="#安装与配置git" aria-hidden="true">#</a></h2><h3 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-hidden="true">#</a></h3><p>现在笔者使用的<code>MacOS</code>系统，是自带<code>Git</code>的。关于Windows系统下安装，请参考如下文章，讲解的非常详细。</p><p>Windows系统Git安装教程（详解Git安装过程）：</p><p><a href="https://link.juejin.cn/?target=https%3A%2F%2Fwww.cnblogs.com%2Fxueweisuoyong%2Fp%2F11914045.html" target="_blank" rel="noreferrer">www.cnblogs.com/xueweisuoyo…</a></p><h3 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-hidden="true">#</a></h3><p>首先需要设置使用Git时候的名字和邮箱，名字需要使用英文</p><p>git config --global <a href="http://user.name" target="_blank" rel="noreferrer">user.name</a> &quot;Firstname Lastname&quot; # 名称 git config --global user.email &quot;<a href="mailto:your_email@example.com" target="_blank" rel="noreferrer">your_email@example.com</a>&quot; # 邮箱</p><h1 id="gitconfig中以如下形式输出文件" tabindex="-1">~/.gitconfig中以如下形式输出文件 <a class="header-anchor" href="#gitconfig中以如下形式输出文件" aria-hidden="true">#</a></h1><p>[user] name = Firstname Lastname email = <a href="mailto:your_email@example.com" target="_blank" rel="noreferrer">your_email@example.com</a> 复制代码</p><p>需要注意的是：</p><ol><li><p>GitHub上公开仓库的时候，名字和邮箱会一同被公开，所以请不要使用不便公开的隐私信息</p></li><li><p>程序员来自世界各地，请使用英文，不要使用汉字；如果不想使用真名，可以使用网站的昵称</p></li></ol><p><strong>如何提高命令输出的可读性</strong>？</p><p>git config --global color.ui auto # 将color.ui 设置成auto 复制代码</p><h3 id="创建账户" tabindex="-1">创建账户 <a class="header-anchor" href="#创建账户" aria-hidden="true">#</a></h3><p>进入创建用户的页面：<a href="https://link.juejin.cn/?target=http%3A%2F%2Fgithub.com%2Fjoin" target="_blank" rel="noreferrer">github.com/join</a></p><p>填写如下的信息在点击<code>Create an accout</code>即可</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/ff235251c6af4e8e923b548dff208d05~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><h3 id="配置ssh" tabindex="-1">配置SSH <a class="header-anchor" href="#配置ssh" aria-hidden="true">#</a></h3><p>GitHub上连接现有仓库的认证，是通过使用了SSH的公开密钥认证方式进行的。现在我们需要创建公开密钥所需的SSH Key，并将其添加到GitHub。</p><p>ssh-keygen -t rsa -C # 创建SSH Key 复制代码</p><p>接下来需要输入两次密码，最终会生成两个文件：</p><ul><li><p>id_rsa：私有密钥</p></li><li><p>id_rsa.pub：公开密钥</p></li></ul><p>下面我们需要在GitHub中添加公开密钥，今后就可以使用私有密钥进行认证。点击右上角的账户设定按钮：</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/6186e3ae3dc34358ad69b8ac14e0a8bc~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><p>进入settings之后，添加新的SSH Key</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/d8fc995e4f00457a8ee5f484f97f8905~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><p>接下来会出现Title和Key两个输入框，在Title中输入适当的密钥名称，Key部分复制上面id_rsa.pub文件中的内容</p><p><code>cat ~/.ssh/id_rsa.pub # 查看内容</code> 复制代码</p><p>添加完成之后，会在我们的邮箱中收到一封提示“公开密钥添加完成”的邮件，确认即可。这样便完成了整个手中的私人密钥和GitHub的认证和通信问题，验证一下：</p><p>ssh -T <a href="mailto:git@github.com" target="_blank" rel="noreferrer">git@github.com</a> 复制代码</p><p>在接下来的页面中输入密码和yes即可完成验证。</p><h2 id="建立仓库" tabindex="-1">建立仓库 <a class="header-anchor" href="#建立仓库" aria-hidden="true">#</a></h2><p>首先我们必须明白一点：<strong>仓库有两种</strong></p><ul><li><p>远程在GitHub上的仓库：远程仓库</p></li><li><p>在自己本地的仓库：本地仓库</p></li></ul><p>本文是以MacOS系统为例，基于Linux；如果是想学习Windows下的仓库创建，请参考下文，讲解的很详细：</p><p>Git使用（10分钟入门）：</p><p><a href="https://link.juejin.cn/?target=https%3A%2F%2Fwww.jianshu.com%2Fp%2F09f243768cf6" target="_blank" rel="noreferrer">www.jianshu.com/p/09f243768…</a></p><h3 id="远程仓库" tabindex="-1">远程仓库 <a class="header-anchor" href="#远程仓库" aria-hidden="true">#</a></h3><p>1、建立远程仓库需要我们先登陆自己的GitHub账号，再进行建仓。</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/24782d0a81e44c01880afe88b4942c44~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><p>2、我们创建一个<code>git_start</code>的仓库</p><ul><li><p>仓库的名字</p></li><li><p>仓库的简单描述</p></li><li><p><strong>不要</strong>在远程仓库添加README.md文件。我们使用手动push的方式来添加</p></li></ul><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/d9e5b6ad22154dd2a2506d98188809d5~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><p>3、仓库解释</p><p>打开上面我们创建好的仓库，会出现如下的内容（先写上注释，后面慢慢解释）</p><p>echo &quot;# git_start&quot; &gt;&gt; <a href="http://README.md" target="_blank" rel="noreferrer">README.md</a> # 往README.md中写入内容 git init # 初始化 git add <a href="http://README.md" target="_blank" rel="noreferrer">README.md</a> # 添加文件 git commit -m &quot;first commit&quot; # 提交并注释 git branch -M main # 提交分支 git remote add origin <a href="mailto:git@github.com" target="_blank" rel="noreferrer">git@github.com</a>:pidada/git_start.git # 建立远程仓库与本地仓库的连接 git push -u origin main # 推送 复制代码</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/48cf5bcefc9a490ebe0a43ede27301c8~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><h3 id="本地仓库" tabindex="-1">本地仓库 <a class="header-anchor" href="#本地仓库" aria-hidden="true">#</a></h3><p>1、建立本地仓库</p><p>所谓的本地仓库，就是你自己电脑客户端的仓库。同样地，笔者在本地建立了同样名字的本地仓库<code>git_start</code>，其实就是个文件夹</p><p><strong>本地仓库要和远程仓库保持一致</strong></p><p>mkdir git_start # 创建文件夹，即仓库 cd git_start # 切换到仓库中 ls # 查看内容，目前是没有任何内容 复制代码</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/793c8d1780d14b798878588c13e0a24e~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><p>2、初始化操作</p><p>echo &quot;学习GitHub的使用，快速入门&quot; &gt;&gt; <a href="http://README.md" target="_blank" rel="noreferrer">README.md</a> # 往文件中写入内容，后面可以更改 git init # 初始化 复制代码</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/7ded2e5360fc4254b4f14eefd61d2c09~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><p>初始化之后会在当前目录下自动生成一个<code>.git</code>的文件。这个文件下存储着管理当前目录内容所需要的仓库数据</p><p>3、查看待提交文档</p><p>通过<code>ls</code>查看已经有了<code>README.md</code>文档</p><p>git status # 查看待提交的文档 复制代码</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/457c5058a7b44547a0c37fb7db29bd52~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><p>4、提交文档</p><p>我们将上面的<code>README.md</code>文档和生成的<code>.git</code>文档一并提交</p><p>git add . # 提交全部文件 git add <a href="http://README.md" target="_blank" rel="noreferrer">README.md</a> # 单独提交一个文件 git commmit -m &quot;2021-1-1&quot; # commit提交，同时写上备注：2021-1-1</p><h1 id="add-和-commit的同步操作" tabindex="-1">add 和 commit的同步操作 <a class="header-anchor" href="#add-和-commit的同步操作" aria-hidden="true">#</a></h1><p>git commit -am &quot;2021-1-1&quot; 复制代码</p><p><strong>注意：执行了add操作，文件还没有被上传到Git远程仓库中，只是提交到了缓存区域</strong></p><p><code>git commit -m &quot;2021-1-1&quot;</code>才是真正地提交内容，同时写上备注：将文件从缓存区提交到远程</p><p>5、建立远程仓库连接并推送</p><p>git remote add origin <a href="mailto:git@github.com" target="_blank" rel="noreferrer">git@github.com</a>:peter/git_start.git # 建立连接 git push -u origin master # 推送到master分支 复制代码</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/62eaf35496204d3d8f7949bff9eddb65~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><p>6、检查</p><p>此时我们刷新远程仓库的页面，会发现页面更新了，也有了内容：</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/3aa2107ed8ca47999730726ced028072~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><p>7、查看提交日志</p><p>git log # 查看提交日志 git log --pretty=short # 只显示一行简述信息 git log <a href="http://README.md" target="_blank" rel="noreferrer">README.md</a> # 只显示指定目录、文件的日志 git log -p <a href="http://README.md" target="_blank" rel="noreferrer">README.md</a> # 只显示指定目录、文件的日志修改前后的改动 复制代码</p><p><code>commit</code>栏旁边显示的是指向这个提交的哈希值。<strong>Git的其他命令中，在指向提交时会用到这个哈希值</strong></p><p>Author栏旁边是Git设置的用户名和邮箱地址</p><p>Date栏显示的是执行日期和时间</p><p>最下面是提交信息，-m 参数后面的信息</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/6cef230666bd479d852949744052e09e~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><p>8、修改<code>README.md</code>文件</p><p>通过vim编辑器修改内容如下：</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/73bb3f8f377640059aa0858689ff4705~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><p>上面使用了Markdown语法，然后我们重新按照上面的命令执行一遍：</p><p>git status # 状态是红色 git add . # 提交到缓存区 git commit -m &quot;<a href="http://xn--README-2g0js76l.md" target="_blank" rel="noreferrer">修改README.md</a>&quot; # 记录提交信息</p><h1 id="git-remote-add-origin-git-github-com-peter-git-start-git-已经建立了连接-所以不必在执行此命令" tabindex="-1">git remote add origin <a href="mailto:git@github.com" target="_blank" rel="noreferrer">git@github.com</a>:peter/git_start.git # 已经建立了连接，所以不必在执行此命令 <a class="header-anchor" href="#git-remote-add-origin-git-github-com-peter-git-start-git-已经建立了连接-所以不必在执行此命令" aria-hidden="true">#</a></h1><p>git push -u origin master # 推到master分支 复制代码</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/607b0a24cc3b49488c0dd704ff00af7c~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><p>回顾下整个操作的过程：</p><ol><li><p>建立远程仓库</p></li><li><p>建立本地仓库</p></li><li><p>初始化本地仓库</p></li><li><p>文档提交到缓存区</p></li><li><p>缓存区推送到远程仓库</p></li></ol><h3 id="重要命令" tabindex="-1">重要命令 <a class="header-anchor" href="#重要命令" aria-hidden="true">#</a></h3><p>我们总结一下上面操作中几个重要的命令：</p><p>1、git status</p><p>查看仓库中文件的状态。如果有新的文件或者原来的文件有修改过，会出现红色</p><p>2、git add</p><p>向缓存区中添加内容，缓存区是提交之前的一个临时区域（Stage或者Index）</p><p>3、git commit  [-m]</p><p>将暂存区中的文件保存仓库的历史记录中；-m参数后面跟上提交信息：<strong>git commit -m &quot;第一次提交&quot;</strong></p><p>4、git log</p><p>查看以往提交日志信息：什么人在什么时候进行了提交或者合并等，以及操作前后有怎样的差别</p><p>git log # 查看日志 git log --pretty=short # 只显示提交信息的第一行 git log <a href="http://README.md" target="_blank" rel="noreferrer">README.md</a> # 查看某个文件的提交信息 git log -p <a href="http://README.md" target="_blank" rel="noreferrer">README.md</a> # -p参数只查看提交的改动部分 复制代码</p><p>5、git diff</p><p>查看工作树、暂存区、最新提交之间的差别。</p><p>git diff # 查看当前工作树和暂存区的差别 git diff HEAD # 查看本次提交和上次提交的差别；HEAD指向当前分支中的最新一次提交的指针 复制代码</p><p>养成习惯：git commit之前先执行git diff HEAD命令来查看本次提交与上次提交之间的差别；HEAD指向当前分支中最新的一次提交的指针。</p><p>6、仓库操作</p><p><code>-u</code>作用：将来运行git pull命令从远程仓库获取内容时，本地仓库就可以直接从origin的master分支中获取内容，不需要添加其他的参数</p><p>git remote add origin <a href="mailto:git@github.com" target="_blank" rel="noreferrer">git@github.com</a>:github/peter/git_start.git # 添加远程仓库 git push # 推送到远程仓库 git push -u origin master # 推送到master分支下 git push -u origin feature_A # 推送到分支A git clone 仓库地址 # 将某个远程仓库的内容复制到本地 git push # 推送 git pull # 获取最新的远程分支内容 复制代码</p><h3 id="分支" tabindex="-1">分支 <a class="header-anchor" href="#分支" aria-hidden="true">#</a></h3><h3 id="master分支" tabindex="-1">master分支 <a class="header-anchor" href="#master分支" aria-hidden="true">#</a></h3><p>master分支是Git默认创建的分支，其他所有的分支都是在这个分支的基础上进行的。</p><ul><li><p>不同的分支单独进行各自的作业</p></li><li><p>该分支的作业完成之后再和master分支合并</p></li></ul><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/c9de61957e1d44d484746d005407ce85~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><p>进行完作业之后的合并操作：</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/9306d8792e294cb296bffb011385f44a~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><h3 id="分支相关命令" tabindex="-1">分支相关命令 <a class="header-anchor" href="#分支相关命令" aria-hidden="true">#</a></h3><p>1、git branch-显示分支</p><p>显示分支一览表：将分支名列表显示出来，同时确认当前所在的分支；标有星号<code>*</code>表示当前分支</p><p>git branch -a # 查看当前分支的相关信息 复制代码</p><p>2、git branch feature-创建分支</p><p>git branch feature 复制代码</p><p>3、git checkout feature-切换分支</p><p>git checkout feature git checkout master # 切换到master分支 git checkout - # 切换到上一个分支 复制代码</p><p>上面两个命令的合并，创建新的分支并切换到新的分支：</p><p>git checkout -b feature # 切换到创建的新分支 复制代码</p><p>4、git merge-合并分支</p><p>假设某个分支已经完成了作业需要和主分支master合并，使用如下语句：</p><p>git checkout master # 切到主分支 git merge --no-off feature-A # 合并分支 复制代码</p><p>5、git log —graph-图的形式查看分支</p><p>通过图表的形式查看提交的内容</p><p>git log --graph 复制代码</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/c8cb3f99dd86478eb859ff026c8a966f~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><h3 id="版本回溯" tabindex="-1">版本回溯 <a class="header-anchor" href="#版本回溯" aria-hidden="true">#</a></h3><p>既然是版本控制系统，那么对于不同版本的管理肯定是至关重要的。<strong>GitHub的另一个特征便是可以灵活地操作不同的历史版本</strong>。借助分散仓库的优势，可以在不影响其他仓库的前提下对历史版本进行操作。</p><p>1、回溯到指定状态</p><p><strong>哈希值只要输入4位以上就可以执行了</strong></p><p>git reset --hard [哈希值] # 添加指定的哈希值，代表某个时间点的状态 复制代码</p><p>2、查看<strong>当前仓库的全部执行过</strong>的操作日志</p><p>记录我们操作的每次命令</p><p>git reflog # 针对当前仓库 git log # 查看以当前状态为终点的历史日志 复制代码</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/78793e9f70024d4590c0787745923456~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><p>所以我们可以先通过<code>git reflog</code>来查看哈希值，再通过<code>git reset —hard [哈希值]</code>回到某个状态</p><p>3、修改上一条提交信息</p><p>使用<code>git commit --amend</code>命令</p><p>git commit --amend 复制代码</p><p>4、压缩历史</p><p>在合并特性分支之前，如果发现已经提交的内容中有拼写等错误，可以先提交一个修改，然后将这个修改包含到前一个提交之中，压缩成一个历史记录</p><p>git rebase -i git rebase -i HEAD~2 # 当前分支下的两个最新历史记录进行压缩 复制代码</p><p>5、添加提交一次完成</p><p>git commit -am &quot;add和commit同时完成&quot; 复制代码</p><h3 id="git-reset详解" tabindex="-1">git reset详解 <a class="header-anchor" href="#git-reset详解" aria-hidden="true">#</a></h3><h4 id="命令" tabindex="-1">命令 <a class="header-anchor" href="#命令" aria-hidden="true">#</a></h4><p>对版本回溯命令的详解。git reset 命令用于回退版本，可以指定回退到某个具体的历史版本。</p><p>git reset 命令语法格式具体如下：</p><p>git reset [--soft | --mixed | --hard] [HEAD] 复制代码</p><p><code>--mixed</code>是<strong>默认参数，可以不带</strong>，用于重置暂存区的文件与上一次的提交（commit）保持一致，工作区文件内容保持不变</p><h4 id="soft" tabindex="-1">soft <a class="header-anchor" href="#soft" aria-hidden="true">#</a></h4><p><code>--soft</code>参数用于回退到某个版本</p><p>git reset --soft HEAD # 回退到上个版本 git reset --soft HEAD~3 # 回退到上上上个版本 复制代码</p><h4 id="hard⚠️" tabindex="-1">hard⚠️ <a class="header-anchor" href="#hard⚠️" aria-hidden="true">#</a></h4><p>！！！⚠️谨慎使用<code>--hard</code> 参数，它会删除回退点之前的所有信息</p><p>git reset --hard HEAD~3 # 回退到上上上个版本 git reset --hard 1de43 # 回退到指定版本 git reset --hard origin/master # 本地状态回退到和远程相同 复制代码</p><h4 id="head" tabindex="-1">HEAD <a class="header-anchor" href="#head" aria-hidden="true">#</a></h4><p>git reset HEAD^ # 回退到所有内容的上一个版本 git reset HEAD^ <a href="http://xn--Git-3v1e1542a.md" target="_blank" rel="noreferrer">Git入门.md</a> # 回退到Git入门.md文件的版本的上一个版本（指定版本的上个版本） git reset 01b42 # 回退到指定版本，需要至少哈希值的前4位；可以通过git reflog命令先查看我们要回退的版本号的哈希值 复制代码</p><p>git reset HEAD还能取消已缓存的内容。当我们对某个文件的内容进行了修改并且已经执行<code>git add</code>之后，我们想取消缓存区的内容，使用如下命令：</p><p>git reset HEAD [filename] 复制代码</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/5042b0c244e449c99e79a5369db4ca72~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p><p><strong>关于HEAD 说明</strong>：</p><ul><li><p>HEAD 表示当前版本</p></li><li><p>HEAD^ 上一个版本</p></li><li><p>HEAD^^ 上上一个版本</p></li><li><p>HEAD^^^ 上上上一个版本</p></li><li><p>以此类推…</p></li></ul><p>可以使用 ～数字表示</p><ul><li><p>HEAD~0 表示当前版本</p></li><li><p>HEAD~1 上一个版本</p></li><li><p>HEAD^2 上上一个版本</p></li><li><p>HEAD^3 上上上一个版本</p></li><li><p>以此类推…</p></li></ul><h4 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-hidden="true">#</a></h4><ul><li><p><code>HEAD</code>指向的版本就是当前版本，因此，Git允许我们在版本的历史之间穿梭，使用命令<code>git reset --hard commit_id</code>。</p></li><li><p>穿梭前，用<code>git log</code>可以查看提交历史，以便确定要回退到哪个版本。</p></li><li><p>要重返未来，用<code>git reflog</code>查看命令历史，以便确定要回到未来的哪个版本。</p></li></ul>',218),o=[a];function c(l,n,h,g,d,s){return i(),e("div",null,o)}const b=t(r,[["render",c]]);export{m as __pageData,b as default};
